 import { useState } from "react";
import { useNavigate, Link } from "react-router-dom";
import PostCard from "../components/PostCard";

function Home() {
  const navigate = useNavigate();

  const [search, setSearch] = useState("");
  const [bookmarks, setBookmarks] = useState(
  JSON.parse(localStorage.getItem("bookmarks")) || []
);

const handleBookmark = (post) => {
  const updated = [...bookmarks, post];

  localStorage.setItem(
    "bookmarks",
    JSON.stringify(updated)
  );

  setBookmarks(updated);
};

  const posts = [
    {
      id: 1,
      title: "MERN Stack Guide",
      readingTime:
"3 min read",
date:
"23 June 2026",
      content: "Learn MERN stack from scratch and build full stack applications.",
      author: "Kavya",
      likes: 12,
      comments: 5,
      image:
        "https://images.unsplash.com/photo-1506744038136-46273834b3fb"
    },
    {
      id: 2,
      title: "React Tutorial",
      readingTime:
"3 min read",
date:
"24 June 2026",
      content: "A complete guide to learn React step by step.",
      author: "Admin",
      likes: 8,
      comments: 3,
      image:
        "https://images.unsplash.com/photo-1633356122544-f134324a6cee"
    },
    {
      id: 3,
      title: "JavaScript Basics",
      readingTime:
"3 min read",
date:
"25 June 2026",
      content: "Understand JavaScript fundamentals.",
      author: "Suresh",
      likes: 6,
      comments: 2,
      image:
        "https://images.unsplash.com/photo-1515879218367-8466d910aaa4"
    }
  ];

  const filteredPosts = posts.filter((post) =>
    post.title.toLowerCase().includes(search.toLowerCase())
  );
   const trendingPosts = [...posts]
  .sort((a, b) => b.likes - a.likes)
  .slice(0, 3);

  return (
    <>
      {/* Hero Section */}
      <section className="hero">
        <div className="hero-content">
          <h1>
            Share Your Ideas.
            <br />
            <span>Inspire the World.</span>
          </h1>

          <p>
            Join thousands of writers and readers sharing
            knowledge, stories and experiences.
          </p>

          <div className="hero-buttons">
            <button
              className="primary-btn"
              onClick={() => navigate("/register")}
            >
              Get Started
            </button>

            <button
              className="secondary-btn"
              onClick={() => navigate("/dashboard")}
            >
              Explore Blogs →
            </button>
          </div>
        </div>

        <div className="hero-image">
          <img
            src="https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQzLR9IWGj6shCWMVoUe0YF5x7qMRnuQno9apNgmLkI6w&s=10"
            alt="Blog Illustration"
          />
        </div>
      </section>

      {/* Search Bar */}
      <div
        style={{
          textAlign: "center",
          margin: "40px 0"
        }}
      >
        <input
          type="text"
          placeholder="Search blogs..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          style={{
            width: "60%",
            padding: "12px",
            borderRadius: "10px",
            border: "1px solid #ccc"
          }}
        />
      </div>
      <h2 className="section-title">
🔥 Trending Blogs
</h2>

<div className="posts-grid">
  {trendingPosts.map((post) => (
    <PostCard
      key={post.id}
      post={post}
    />
  ))}
</div>

      <h2 className="section-title">
        Latest Blog Posts
      </h2>

      <div className="posts-grid">
        {filteredPosts.length > 0 ? (
          filteredPosts.map((post) => (
            <Link
              key={post.id}
              to={`/post/${post.id}`}
              style={{
                textDecoration: "none",
                color: "inherit"
              }}
            >
              <PostCard post={post} />
            </Link>
          ))
        ) : (
          <h3
            style={{
              textAlign: "center"
            }}
          >
            No blogs found
          </h3>
        )}
      </div>
    </>
  );
}

export default Home;
